#!/bin/bash
# AEON IOT RESOLVER
# Decodes ISM/IoT signals using rtl_433 and pipes them to the Aeon Monitor.

CYAN="\x1b[38;5;51m"
AMBER="\x1b[38;5;214m"
RESET="\x1b[0m"
BOLD="\x1b[1m"

echo -e "${CYAN}${BOLD}━┫ AEON IOT RESOLVER ACTIVE ┣━${RESET}"

FREQ=${1:-915M}
OUT_FRAME="iot_residue.frame"

if ! command -v rtl_433 &> /dev/null; then
    echo -e "${AMBER}ERROR: rtl_433 not found. Please install rtl_433.${RESET}"
    exit 1
fi

echo -e "${CYAN}  HUNTING IN: ${AMBER}${FREQ}${RESET}"

# AEON INTELLIGENCE PIPELINE: Chain rtl_433 directly to the collector.
# The collector handles JSON parsing and PleromaticFrame forgery.
rtl_433 -M level -f "$FREQ" -F json | ./target/release/iot-residue-collector
